import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "L DHANUSH RAJ",
  description: "AI Enthusiast, Developer & Entrepreneur",
};

import LayoutWrapper from "@/components/LayoutWrapper";

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="anonymous" />
        <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@100..900&family=Inter:wght@100..900&display=swap" rel="stylesheet" />
      </head>
      <body className="antialiased overflow-x-hidden bg-white text-[#333333]">
        <LayoutWrapper>{children}</LayoutWrapper>
      </body>
    </html>
  );
}

"use client";

import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import React, { ReactNode } from "react";

interface CrazyCardProps {
    children: ReactNode;
    className?: string;
}

export default function CrazyCard({ children, className = "" }: CrazyCardProps) {
    const x = useMotionValue(0);
    const y = useMotionValue(0);

    const mouseXSpring = useSpring(x);
    const mouseYSpring = useSpring(y);

    const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["5deg", "-5deg"]);
    const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-5deg", "5deg"]);

    const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
        const rect = e.currentTarget.getBoundingClientRect();
        const width = rect.width;
        const height = rect.height;
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;

        const xPct = mouseX / width - 0.5;
        const yPct = mouseY / height - 0.5;

        x.set(xPct);
        y.set(yPct);
    };

    const handleMouseLeave = () => {
        x.set(0);
        y.set(0);
    };

    return (
        <motion.div
            onMouseMove={handleMouseMove} // Keep for glow effect
            onMouseLeave={handleMouseLeave} // Keep for glow effect
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            whileHover={{ y: -10, scale: 1.02 }}
            className={`glass-card group relative p-8 bg-white border border-[#333333]/5 shadow-xl shadow-[#5a7d9a]/5 hover:shadow-2xl hover:shadow-[#5a7d9a]/10 hover:border-primary transition-all duration-500 overflow-hidden ${className}`}
        >
            {/* Corner Accent */}
            <div className="absolute top-0 right-0 w-8 h-8 opacity-10 group-hover:opacity-100 transition-opacity">
                <div className="absolute top-0 right-0 w-full h-[1px] bg-primary" />
                <div className="absolute top-0 right-0 w-[1px] h-full bg-primary" />
            </div>

            <div className="relative z-10 h-full">
                {children}
            </div>

            {/* Dynamic Hover Glow - Technical Blue */}
            <motion.div
                className="absolute inset-0 z-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500"
                style={{
                    background: useTransform(
                        [mouseXSpring, mouseYSpring],
                        ([xVal, yVal]) => `radial-gradient(circle at ${((xVal as number) + 0.5) * 100}% ${((yVal as number) + 0.5) * 100}%, rgba(59, 130, 246, 0.08) 0%, transparent 80%)`
                    )
                }}
            />
        </motion.div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { motion, useSpring, useMotionValue } from "framer-motion";

export default function CustomCursor() {
    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);

    const springConfig = { damping: 35, stiffness: 300, mass: 0.6 };
    const springX = useSpring(mouseX, springConfig);
    const springY = useSpring(mouseY, springConfig);

    const [isHovering, setIsHovering] = useState(false);
    const [hoverText, setHoverText] = useState("");

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            mouseX.set(e.clientX);
            mouseY.set(e.clientY);
        };

        const handleMouseOver = (e: MouseEvent) => {
            const target = e.target as HTMLElement;
            if (target.tagName === "BUTTON" || target.tagName === "A" || target.closest(".magnetic-item") || target.closest("button")) {
                setIsHovering(true);
                const text = target.innerText?.split('\n')[0] || "EXPLORE";
                setHoverText(`>> ${text.toUpperCase()}`);
            } else {
                setIsHovering(false);
                setHoverText("");
            }
        };

        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mouseover", handleMouseOver);

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            window.removeEventListener("mouseover", handleMouseOver);
        };
    }, []);

    return (
        <div className="hidden md:block pointer-events-none fixed inset-0 z-[9999]">
            {/* Center Dot - Charcoal in Light Mode */}
            <motion.div
                className="absolute w-1.5 h-1.5 bg-[#333333] rounded-full shadow-[0_0_10px_rgba(0,0,0,0.1)]"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isHovering ? 2 : 1,
                    backgroundColor: isHovering ? "#5a7d9a" : "#333333",
                }}
            />

            {/* Technical Outer Frame - Light Mode */}
            <motion.div
                className="absolute w-12 h-12 border border-[#333333]/10 rounded-full"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isHovering ? 1.5 : 1,
                    borderColor: isHovering ? "rgba(90, 125, 154, 0.3)" : "rgba(51, 51, 51, 0.1)",
                    borderWidth: isHovering ? "2px" : "1px",
                }}
                transition={{ type: "spring", damping: 40, stiffness: 150 }}
            />

            {/* Data Label - Outfit Font */}
            <motion.div
                className="absolute text-[8px] font-black tracking-[0.3em] text-[#333333] whitespace-nowrap pt-2 luxury-text"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "28px",
                    translateY: "12px",
                }}
                animate={{
                    opacity: isHovering ? 1 : 0,
                    x: isHovering ? 36 : 28,
                }}
            >
                {hoverText}
            </motion.div>

            {/* Corner Markers - Premium Detail */}
            {isHovering && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.3 }}
                    style={{
                        x: springX,
                        y: springY,
                        translateX: "-50%",
                        translateY: "-50%",
                    }}
                    className="absolute w-20 h-20"
                >
                    <div className="absolute top-0 left-0 w-3 h-[1px] bg-primary" />
                    <div className="absolute top-0 left-0 w-[1px] h-3 bg-primary" />
                    <div className="absolute bottom-0 right-0 w-3 h-[1px] bg-primary" />
                    <div className="absolute bottom-0 right-0 w-[1px] h-3 bg-primary" />
                </motion.div>
            )}
        </div>
    );
}

